import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.File;
import java.util.HashMap;
import java.util.Map;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NamedNodeMap;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

public class XMLParser {

    public static Map<String, String> parseConfigFile(String fileName) {
        Map<String, String> configMap = new HashMap<>();

        try {
            File xmlFile = new File(fileName);
            DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance();
            dbFactory.setIgnoringElementContentWhitespace(true); 
            DocumentBuilder dBuilder = dbFactory.newDocumentBuilder();
            Document doc = dBuilder.parse(xmlFile);

            doc.getDocumentElement().normalize();
            Element root = doc.getDocumentElement();
            parseNode(root, configMap);

        } catch (Exception e) {
            e.printStackTrace();
        }

        return configMap;
    }

    private static void parseNode(Node node, Map<String, String> configMap) {
        if (node.getNodeType() == Node.ELEMENT_NODE) {
            if (node.hasAttributes()) {
                NamedNodeMap nodeMap = node.getAttributes();
                for (int i = 0; i < nodeMap.getLength(); i++) {
                    Node tempNode = nodeMap.item(i);
                    configMap.put(tempNode.getNodeName(), tempNode.getNodeValue());
                }
            }

            if (node.hasChildNodes()) {
                NodeList nodeList = node.getChildNodes();
                for (int j = 0; j < nodeList.getLength(); j++) {
                    parseNode(nodeList.item(j), configMap);
                }
            }
        }
    }

}